INSERT INTO pages (slug, title, subtitle) VALUES ('about', 'About LynxiGlam', 'Salon-worthy nails and lashes, minus the salon.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('about', 'Our Story', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'LynxiGlam started with one stubborn idea: getting a flawless set of lashes or nails shouldn''t cost you an afternoon or a fortune. What began as a search for a magnetic lash that actually held led us to reinvent at-home beauty from the ground up.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Today we design press-on nails, magnetic lashes, and quick-press manicures that go on in minutes, wear for weeks, and look like you just left the chair. No appointments, no glue disasters, no compromise.', 1);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('about', 'What We Believe', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Beauty should be fast, forgiving, and fun. Every set is built to be reusable, refill-friendly, and kind to your natural nails and lash line.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'We''re proudly certified cruelty-free by Leaping Bunny, and we obsess over the details so you can get ready in ten minutes and feel unstoppable for two weeks.', 1);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('about', 'Made For Everyone', 2);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'From a first-timer nervous about their first press-on to the pro who changes their set every week, LynxiGlam is built to fit real life. Hundreds of shapes, lengths, and styles mean there''s a look for every mood.', 0);
INSERT INTO pages (slug, title, subtitle) VALUES ('shipping', 'Shipping Information', 'Everything about how and when your order arrives.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('shipping', 'Processing Times', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Orders are processed within 1–2 business days. During new launches, holidays, and promotions, processing can take slightly longer, but we always work to get your glam out the door fast.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'You''ll receive a confirmation email as soon as your order is placed, and a second email with tracking once it ships.', 1);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('shipping', 'Domestic Shipping', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'We offer FREE U.S. economy shipping on orders of $65 or more. Under that, economy shipping is a flat rate calculated at checkout. Expedited and express options are available for when you need your set in a hurry.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('shipping', 'International Shipping', 2);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'We ship to most countries worldwide. International rates and delivery windows are calculated at checkout based on your destination. Please note that duties, taxes, and customs fees are the responsibility of the recipient.', 0);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('shipping', 'When will my order ship?', 'Most orders leave our warehouse within 1–2 business days. You''ll get a tracking email the moment it ships.', 0);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('shipping', 'Do you offer free shipping?', 'Yes — U.S. orders of $65+ qualify for free economy shipping automatically at checkout.', 1);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('shipping', 'How long does delivery take?', 'U.S. economy delivery typically takes 3–7 business days after shipping. International times vary by destination.', 2);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('shipping', 'Can I change my shipping address after ordering?', 'Reach out to our Help Center right away. If your order hasn''t shipped yet, we''ll do our best to update it.', 3);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('shipping', 'Who pays customs fees on international orders?', 'Any duties, taxes, or customs charges are the responsibility of the recipient and are not included in your order total.', 4);
INSERT INTO pages (slug, title, subtitle) VALUES ('returns', 'Returns & Exchanges', 'Not in love? Here''s how to make it right.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('returns', 'Our Policy', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'We want you to love your set. If something isn''t right, you may request a return or exchange within 30 days of delivery. For hygiene reasons, lashes and nails must be unused, unopened, and in their original packaging.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Final-sale items, mystery bundles, and gift cards are not eligible for return.', 1);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('returns', 'How To Start a Return', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Head to our Help Center and submit a return request with your order number and email. Once approved, we''ll email you a prepaid label and instructions.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Refunds are issued to your original payment method within 5–10 business days after we receive and inspect your return.', 1);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('returns', 'Damaged or Wrong Items', 2);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'If your order arrives damaged or you received the wrong item, contact us within 7 days with a photo and we''ll send a replacement at no cost to you.', 0);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('returns', 'How long do I have to return an item?', 'You can request a return or exchange within 30 days of your delivery date.', 0);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('returns', 'Can I return an opened set?', 'For hygiene reasons, lashes and nails must be unused, unopened, and in original packaging to qualify.', 1);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('returns', 'How do I start a return?', 'Submit a request through our Help Center with your order number and email, and we''ll send a prepaid label once approved.', 2);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('returns', 'When will I get my refund?', 'Refunds post to your original payment method within 5–10 business days after we receive your return.', 3);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('returns', 'What if my order arrived damaged?', 'Contact us within 7 days with a photo and we''ll ship a free replacement.', 4);
INSERT INTO pages (slug, title, subtitle) VALUES ('help', 'Help Center', 'Answers, fast — so you can get back to glam.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('help', 'Get In Touch', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Our support team is here Monday through Friday, 9am–5pm PT. The fastest way to reach us is through the contact form in this Help Center — include your order number and we''ll get back to you within one business day.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('help', 'Popular Topics', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Most questions are about order tracking, shipping windows, returns, and application tips. Check the FAQ below or explore our dedicated Shipping, Returns, and How-To Apply pages for step-by-step guidance.', 0);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('help', 'How do I contact support?', 'Use the contact form in the Help Center with your order number. We reply within one business day, Monday–Friday.', 0);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('help', 'Where''s my order?', 'Visit Track My Order and enter your order number and email to see live status, or check the tracking link in your shipping email.', 1);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('help', 'Do you offer discounts?', 'Yes — join LynxiGlam Rewards and the Insider Plus membership for credits, early access, and members-only pricing.', 2);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('help', 'Are your products cruelty-free?', 'Absolutely. Every LynxiGlam product is certified cruelty-free by Leaping Bunny.', 3);
INSERT INTO pages (slug, title, subtitle) VALUES ('track', 'Track My Order', 'Follow your glam from our door to yours.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('track', 'Find Your Tracking', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Every order ships with a tracking number sent to the email you used at checkout. Look for a message with the subject line "Your LynxiGlam order is on the way" and tap the tracking link inside.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'If you created an account, you can also view live status anytime under Order History in your account dashboard.', 1);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('track', 'Can''t Find Your Email?', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Check your spam and promotions folders first. Still nothing? Contact our Help Center with your order number and we''ll resend your tracking details right away.', 0);
INSERT INTO pages (slug, title, subtitle) VALUES ('store-locator', 'Store Locator', 'Find LynxiGlam on shelves near you.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('store-locator', 'Where To Buy', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Beyond glamnetic.com, you can shop select LynxiGlam favorites at major beauty retailers nationwide, including Ulta Beauty, Sephora, and Ulta Beauty at Target.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Availability varies by location and season, so we recommend calling ahead to confirm your favorite style is in stock.', 1);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('store-locator', 'Retail Partners', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Our retail assortment features best-selling press-on nails, magnetic lashes, and application essentials. For the full catalog — including web-exclusive collections and collabs — shop online.', 0);
INSERT INTO pages (slug, title, subtitle) VALUES ('loyalty', 'LynxiGlam Rewards', 'Earn points every time you glam.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('loyalty', 'How It Works', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Join LynxiGlam Rewards for free and start earning points on every purchase, review, and referral. Points add up fast and convert straight into store credit at checkout.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Create an account or log in, and your points balance follows you across every order.', 1);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('loyalty', 'Ways To Earn', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Earn points for placing orders, writing product reviews, following us on social, celebrating your birthday, and referring friends. The more you engage, the faster your rewards grow.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('loyalty', 'Redeem Your Points', 2);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Cash in your points for discounts on future orders — you choose how much to apply at checkout. Points never expire as long as your account stays active.', 0);
INSERT INTO pages (slug, title, subtitle) VALUES ('membership', 'LynxiGlam Insider Plus', 'Our members-only club for serious glam.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('membership', 'Membership Perks', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Insider Plus is our premium membership built for regulars. Members earn 15% back in store credit on every order, enjoy free U.S. shipping with no minimum, and unlock early access to new launches before anyone else.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'You''ll also get a $10 welcome credit and a free nail set at sign-up — a value that covers your membership on day one.', 1);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('membership', 'How To Join', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Sign up in seconds during checkout or from your account dashboard. Your perks activate immediately, and you can manage or cancel your membership anytime.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('membership', 'Is It Worth It?', 2);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'If you restock more than a couple times a year, the store credit and free shipping typically pay for the membership several times over. Do the math — most members come out ahead fast.', 0);
INSERT INTO pages (slug, title, subtitle) VALUES ('glamfam', 'VIP GlamFam Group', 'Where the LynxiGlam community lives.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('glamfam', 'Join The GlamFam', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'The VIP GlamFam Group is our private community of nail and lash lovers who get first looks, insider polls, and exclusive drops. It''s the place to share your sets, swap application hacks, and help shape what we make next.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('glamfam', 'Member Benefits', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'GlamFam members vote on upcoming shades, test early launches, and score surprise perks throughout the year. Your feedback goes straight to our design team.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Membership is free — just join the group and introduce your favorite look.', 1);
INSERT INTO pages (slug, title, subtitle) VALUES ('wholesale', 'Wholesale & Partnerships', 'Bring LynxiGlam to your shelves.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('wholesale', 'Stock LynxiGlam', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'We partner with salons, boutiques, and beauty retailers who want to offer their customers salon-quality press-ons and magnetic lashes. Our wholesale program includes competitive pricing, marketing support, and a curated best-seller assortment.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('wholesale', 'Who We Work With', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'From independent nail studios to national chains, we tailor our program to fit your business. Minimum order quantities and tiered pricing are available on request.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('wholesale', 'Apply To Partner', 2);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Ready to carry LynxiGlam? Submit a wholesale inquiry with your business details and our partnerships team will follow up within 3–5 business days.', 0);
INSERT INTO pages (slug, title, subtitle) VALUES ('apply', 'How To Apply Press-Ons', 'A flawless set in about ten minutes.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('apply', 'Prep Your Nails', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Start with clean, dry, oil-free nails. Push back your cuticles, lightly buff the surface of each natural nail, and wipe with the included prep pad. A little prep is the secret to long-lasting wear.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('apply', 'Size & Place', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Lay out your press-ons and match each one to a natural nail — pick a size that covers the nail without touching the skin. Apply a thin, even layer of glue to both your natural nail and the press-on for the strongest hold.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Press each nail on at a slight downward angle toward the cuticle, then hold firmly for 15–20 seconds.', 1);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('apply', 'Finish & Shape', 2);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Once all ten are set, gently file to your preferred length and shape. Avoid water and heavy hand-washing for the first hour to let the glue fully cure.', 0);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('apply', 'How long does application take?', 'Most people finish a full set in about ten minutes once they''ve done it a couple of times.', 0);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('apply', 'How long will my press-ons last?', 'With proper prep and glue application, a set can last up to two weeks.', 1);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('apply', 'What if a nail doesn''t fit perfectly?', 'Choose the closest size that doesn''t touch your skin, then file the sides and free edge to customize the fit.', 2);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('apply', 'Can I reuse my press-ons?', 'Yes — remove them gently, clean off old glue, and store them in the tray for another wear.', 3);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('apply', 'Do I have to use glue?', 'Glue gives the longest hold, but adhesive tabs are a great no-glue option for shorter, gentler wear.', 4);
INSERT INTO pages (slug, title, subtitle) VALUES ('remove', 'How To Remove Press-Ons', 'Take them off safely — no damage, no drama.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('remove', 'The Soak Method', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Fill a bowl with warm, soapy water and soak your fingertips for 10–15 minutes. This loosens the adhesive so your press-ons lift away without pulling on your natural nail.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Gently wiggle each nail free from the sides. Never force or pry — if one resists, soak a little longer.', 1);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('remove', 'Clean & Condition', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Once removed, buff away any leftover glue and wash your hands. Follow with cuticle oil or a nourishing hand cream to rehydrate your nails and skin.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('remove', 'Save For Next Time', 2);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Peel any remaining adhesive off the press-ons, wipe them clean, and store them back in the tray. Cared-for sets can be worn again and again.', 0);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('remove', 'How do I remove press-ons without damaging my nails?', 'Soak in warm, soapy water for 10–15 minutes, then gently wiggle each nail free — never force or pry.', 0);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('remove', 'Can I use acetone?', 'A brief soak in acetone or remover can speed things up, but warm soapy water is gentler on your natural nails.', 1);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('remove', 'A nail won''t budge — what do I do?', 'Soak longer. Forcing it can peel layers off your natural nail, so patience is key.', 2);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('remove', 'How do I care for my nails after removal?', 'Buff off leftover glue and apply cuticle oil or hand cream to rehydrate.', 3);
INSERT INTO pages (slug, title, subtitle) VALUES ('quick-press-tips', 'Quick Press Mani Application Tips', 'Pro tricks for your fastest, longest-lasting set yet.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('quick-press-tips', 'Prep Like A Pro', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Your manicure is only as good as your prep. Clean, buff, and dehydrate each nail before you start — even a trace of oil or lotion can cut your wear time in half.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('quick-press-tips', 'Nail The Application', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Work one hand at a time so nothing slips before it sets. Apply firm, even pressure from cuticle to tip and hold each nail longer than you think you need to. A tight, bubble-free bond is what makes a Quick Press Mani last.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('quick-press-tips', 'Make It Last', 2);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Wear gloves for dishes and cleaning, keep your hands out of long hot soaks, and swipe on cuticle oil daily to keep edges from lifting. Small habits add days of wear.', 0);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('quick-press-tips', 'How long does a Quick Press Mani last?', 'With good prep and daily care, most sets wear beautifully for up to two weeks.', 0);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('quick-press-tips', 'How do I stop my nails from lifting early?', 'Dehydrate before applying, hold firm pressure while setting, and wear gloves for wet work.', 1);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('quick-press-tips', 'Can I shower with my Quick Press Mani?', 'Yes — just avoid long, hot soaks in the first 24 hours while the adhesive fully cures.', 2);
INSERT INTO faq_items (page_slug, question, answer, position) VALUES ('quick-press-tips', 'What''s the biggest application mistake?', 'Skipping prep. Any leftover oil or lotion dramatically shortens how long your set holds.', 3);
INSERT INTO pages (slug, title, subtitle) VALUES ('terms', 'Terms of Service', 'The fine print for using LynxiGlam.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('terms', 'Agreement To Terms', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'By accessing or purchasing from glamnetic.com, you agree to these Terms of Service and all policies referenced within them. If you do not agree, please do not use the site.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'We may update these terms from time to time. Continued use of the site after changes are posted constitutes your acceptance of the revised terms.', 1);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('terms', 'Orders & Pricing', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'All orders are subject to acceptance and availability. We reserve the right to refuse or cancel any order, and to correct pricing errors even after an order has been placed. Prices and promotions are subject to change without notice.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('terms', 'Intellectual Property', 2);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'All content on this site — including logos, imagery, product designs, and copy — is the property of LynxiGlam and protected by applicable intellectual property laws. You may not reproduce or reuse it without written permission.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('terms', 'Limitation Of Liability', 3);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'LynxiGlam is not liable for any indirect or incidental damages arising from the use of our products or site. Our products are intended for cosmetic use only; discontinue use if irritation occurs.', 0);
INSERT INTO pages (slug, title, subtitle) VALUES ('privacy', 'Privacy Policy', 'How we collect, use, and protect your information.');
INSERT INTO page_sections (page_slug, heading, position) VALUES ('privacy', 'Information We Collect', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'We collect information you provide directly — such as your name, email, shipping address, and payment details — as well as data gathered automatically, like your device type, browsing activity, and cookies.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('privacy', 'How We Use Your Data', 1);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Your information helps us process orders, provide customer support, personalize your experience, and send updates you''ve opted into. We never sell your personal data.', 0);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'You can unsubscribe from marketing emails at any time using the link in any message.', 1);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('privacy', 'Cookies & Tracking', 2);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'We use cookies and similar technologies to keep your cart, remember preferences, and understand how the site is used. You can manage cookie preferences through your browser settings.', 0);
INSERT INTO page_sections (page_slug, heading, position) VALUES ('privacy', 'Your Rights', 3);
INSERT INTO page_section_body (section_id, paragraph, position) VALUES (@page_section_id, 'Depending on where you live, you may have the right to access, correct, or delete your personal information. To make a request, contact us through our Help Center and we''ll respond in line with applicable law.', 0);
INSERT INTO blog_posts (handle, title, excerpt, image, author, published_at) VALUES ('make-your-press-ons-last-2-weeks', 'How To Make Your Press-Ons Last 2+ Weeks', 'A few small habits at application are the difference between three days and three weeks of flawless wear.', 'CitrusCoast_1.webp', 'Team LynxiGlam', '2026-06-20');
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('make-your-press-ons-last-2-weeks', 'The single biggest factor in press-on longevity happens before you ever pick up the glue: prep. Push back your cuticles, lightly buff the shine off your natural nail, and wipe each nail with an alcohol pad. Oils are the enemy of adhesion, so this quick degrease removes the invisible layer that causes lifting on day two.', 0);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('make-your-press-ons-last-2-weeks', 'Sizing matters more than most people think. Each nail should sit flush against your cuticle line and cover from sidewall to sidewall without pressing into the skin. If you are between sizes, always go down — a slightly smaller nail bonds tighter and looks more natural than one that overhangs and catches on everything.', 1);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('make-your-press-ons-last-2-weeks', 'When you apply the adhesive, use a thin, even layer on both your natural nail and the back of the press-on. Press firmly and hold for a full 30 seconds per nail. That sustained pressure is what activates a strong, gap-free bond. Rushing this step is the number one reason a set pops off early.', 2);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('make-your-press-ons-last-2-weeks', 'For the days that follow, treat your hands with a little care. Wear gloves for dishes and cleaning, avoid prolonged soaking, and dab cuticle oil around (not under) the nail to keep skin healthy without loosening the glue. Do this and a two-week wear becomes the norm rather than the exception.', 3);
INSERT INTO blog_posts (handle, title, excerpt, image, author, published_at) VALUES ('5-summer-nail-trends', '5 Summer Nail Trends We''re Obsessed With', 'From citrus-bright tips to milky chrome, these are the manicures defining the season.', 'SaltyWaves_1.webp', 'Team LynxiGlam', '2026-06-12');
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('5-summer-nail-trends', 'Summer is the season to be bold, and this year the trends are leaning playful, glossy, and unapologetically fun. If your winter sets skewed neutral, consider this your permission slip to experiment. Here are the five looks we cannot stop reaching for.', 0);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('5-summer-nail-trends', 'First up: citrus brights. Think zesty orange, lime, and sunny yellow in a high-shine finish. Worn on a short square or oval, these shades read fresh rather than loud and pair effortlessly with a tan and a sundress.', 1);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('5-summer-nail-trends', 'Second, milky chrome. A sheer, milky base topped with a whisper of pearlescent shimmer gives that expensive, lit-from-within glow. It is the quiet-luxury manicure that flatters every skin tone and photographs beautifully in golden-hour light.', 2);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('5-summer-nail-trends', 'Rounding out the list: micro-French tips in candy pastels, ocean-inspired blues with a wet-look topcoat, and delicate aura nails that blend two shades into a soft glowing center. Mix and match across your fingers if you cannot commit to just one — an eclectic set is very on-trend this year.', 3);
INSERT INTO blog_posts (handle, title, excerpt, image, author, published_at) VALUES ('magnetic-lashes-101', 'Magnetic Lashes 101: A Beginner''s Guide', 'No glue, no waiting to dry, no mess — here''s everything you need to master magnetic lashes on your first try.', 'Magnetic_Lashes.jpg', 'Team LynxiGlam', '2026-05-28');
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('magnetic-lashes-101', 'Magnetic lashes swap messy adhesive for a magnetic eyeliner that your lashes snap onto — no drying time, no fumbling, and no stinging glue near your eyes. If you have avoided falsies because application felt intimidating, this system was built for you.', 0);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('magnetic-lashes-101', 'Start by applying two coats of the magnetic liner along your upper lash line, just as you would any liquid liner. Let the second coat set for about a minute until it goes from wet-shiny to matte. This tacky-dry stage is the sweet spot where the magnets grip best.', 1);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('magnetic-lashes-101', 'Next, position the lash from the outer corner inward, gently pressing it down onto the liner. You will feel it click into place. Adjust as needed — because there is no glue, you can lift and reposition until it sits exactly where you want it. Beginners often find it easiest to trim the band to their eye width first.', 2);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('magnetic-lashes-101', 'To remove, simply peel the lash off gently from the outer corner and wipe away the liner with an oil-free micellar water. Store your lashes back on their tray to keep the band''s shape, and with proper care a single pair can be reworn 30 times or more.', 3);
INSERT INTO blog_posts (handle, title, excerpt, image, author, published_at) VALUES ('guide-to-nail-shapes', 'The LynxiGlam Guide to Nail Shapes', 'Almond, coffin, square, or round — here''s how to choose the shape that flatters your hands and fits your lifestyle.', 'LaPerle_1.webp', 'Team LynxiGlam', '2026-05-15');
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('guide-to-nail-shapes', 'The right nail shape can lengthen your fingers, complement your natural nail bed, and hold up to your daily routine. With so many options it helps to understand what each shape actually does before you commit to a set.', 0);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('guide-to-nail-shapes', 'Almond is the universally flattering choice — tapered sides and a rounded peak that elongates the hand and feels elegant without being fragile. Coffin (also called ballerina) takes that taper and squares off the tip for a bold, editorial look that shines at longer lengths.', 1);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('guide-to-nail-shapes', 'If you prefer something lower-maintenance, square and squoval shapes offer a clean, modern edge with maximum durability, making them ideal for anyone who types, cooks, or works with their hands all day. Round is the shortest and most natural-looking option, mirroring the curve of your cuticle for an understated everyday manicure.', 2);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('guide-to-nail-shapes', 'When in doubt, consider your natural nail bed and how active your hands are. Wider beds are balanced beautifully by almond and oval, while shorter shapes like round and square keep things practical. There is no wrong answer — the best shape is the one you feel confident wearing.', 3);
INSERT INTO blog_posts (handle, title, excerpt, image, author, published_at) VALUES ('remove-press-ons-without-damage', 'How To Remove Press-Ons Without Damage', 'Never peel them off — this gentle soak-off method keeps your natural nails strong and healthy between sets.', 'AperitivoHour_1.webp', 'Team LynxiGlam', '2026-05-02');
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('remove-press-ons-without-damage', 'We get it — at the end of a long wear it is tempting to just pick at a lifting edge and pull. Please don''t. Peeling press-ons off dry takes layers of your natural nail with them, leaving your beds thin, weak, and sensitive. The good news is a proper removal takes about fifteen minutes and keeps your nails intact.', 0);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('remove-press-ons-without-damage', 'Start by filing off the top shine of each press-on to break the seal, then soak your fingertips in a bowl of warm water with a few drops of gentle soap or a splash of acetone for ten to fifteen minutes. The warmth loosens the adhesive so the nails begin to lift on their own.', 1);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('remove-press-ons-without-damage', 'Once softened, use a wooden cuticle stick to gently nudge under each edge and coax the nail off. If you feel any resistance, stop and soak longer — the nail should release with almost no pressure. Never force it.', 2);
INSERT INTO blog_post_body (post_handle, paragraph, position) VALUES ('remove-press-ons-without-damage', 'Finish by buffing away any leftover glue, washing your hands, and flooding your natural nails and cuticles with oil. Give your nails a day to breathe before your next set, and they will stay strong enough to rock press-ons on repeat.', 3);
